  output        io_out_valid,
  output [4:0]  io_out_bits_addr,
  output [31:0] io_out_bits_data
);

  wire _grant_T = io_in_0_valid | io_in_1_valid;
  wire _io_out_valid_T = _grant_T | io_in_2_valid;
  assign io_in_1_ready = ~io_in_0_valid;
