module IBus2Axi(
  input          clock,
                 reset,
                 io_ibus_valid,
  output         io_ibus_ready,
  input  [31:0]  io_ibus_addr,
  output [127:0] io_ibus_rdata,
  output         io_ibus_fault_valid,
  input          io_axi_addr_ready,
  output         io_axi_addr_valid,
  output [31:0]  io_axi_addr_bits_addr,
  input          io_axi_data_valid,
  input  [127:0] io_axi_data_bits_data,
  input  [1:0]   io_axi_data_bits_resp
);

  reg          sraddrActive;
  reg  [31:0]  saddrReg;
  reg  [127:0] sdata;
  reg  [1:0]   sresp;
  reg          sdataValid;
  wire [31:0]  saddr = {io_ibus_addr[31:4], 4'h0};
  wire         io_ibus_ready_0 =
    (io_axi_data_valid & sraddrActive | sdataValid) & saddr == saddrReg;
  wire         io_axi_addr_valid_0 =
    io_ibus_valid & ~sraddrActive & (~sdataValid | saddr != saddrReg);
  wire         _saddrReg_T = io_axi_addr_ready & io_axi_addr_valid_0;
  always @(posedge clock or posedge reset) begin
    if (reset) begin
      sraddrActive <= 1'h0;
      saddrReg <= 32'h0;
      sdata <= 128'h0;
      sresp <= 2'h0;
      sdataValid <= 1'h0;
    end
    else begin
      sraddrActive <= ~io_axi_data_valid & (_saddrReg_T | sraddrActive);
      if (_saddrReg_T)
        saddrReg <= saddr;
      if (io_axi_data_valid) begin
        sdata <= io_axi_data_bits_data;
        sresp <= io_axi_data_bits_resp;
      end
      sdataValid <=
        io_axi_data_valid
          ? ~io_ibus_ready_0
          : ~(io_ibus_ready_0 & io_ibus_valid | _saddrReg_T) & sdataValid;
    end
  end // always @(posedge, posedge)
  `ifdef ENABLE_INITIAL_REG_
    `ifdef FIRRTL_BEFORE_INITIAL
      `FIRRTL_BEFORE_INITIAL
    `endif // FIRRTL_BEFORE_INITIAL
    logic [31:0] _RANDOM[0:5];
    initial begin
      `ifdef INIT_RANDOM_PROLOG_
        `INIT_RANDOM_PROLOG_
      `endif // INIT_RANDOM_PROLOG_
      `ifdef RANDOMIZE_REG_INIT
        for (logic [2:0] i = 3'h0; i < 3'h6; i += 3'h1) begin
          _RANDOM[i] = `RANDOM;
        end
        sraddrActive = _RANDOM[3'h0][0];
        saddrReg = {_RANDOM[3'h0][31:1], _RANDOM[3'h1][0]};
        sdata =
          {_RANDOM[3'h1][31:1],
           _RANDOM[3'h2],
           _RANDOM[3'h3],
           _RANDOM[3'h4],
           _RANDOM[3'h5][0]};
        sresp = _RANDOM[3'h5][2:1];
        sdataValid = _RANDOM[3'h5][3];
      `endif // RANDOMIZE_REG_INIT
      if (reset) begin
        sraddrActive = 1'h0;
        saddrReg = 32'h0;
        sdata = 128'h0;
        sresp = 2'h0;
        sdataValid = 1'h0;
      end
    end // initial
    `ifdef FIRRTL_AFTER_INITIAL
      `FIRRTL_AFTER_INITIAL
    `endif // FIRRTL_AFTER_INITIAL
  `endif // ENABLE_INITIAL_REG_
  assign io_ibus_ready = io_ibus_ready_0;
  assign io_ibus_rdata = sdata;
  assign io_ibus_fault_valid =
    io_ibus_ready_0 & (|(io_axi_data_valid ? io_axi_data_bits_resp : sresp));
  assign io_axi_addr_valid = io_axi_addr_valid_0;
  assign io_axi_addr_bits_addr = saddr;
endmodule

